210	func normalizeReadinessStringList(items []string) []string {
211		if len(items) == 0 {
212			return nil
213		}
214		out := make([]string, 0, len(items))
215		for _, item := range items {
216			item = strings.TrimSpace(item)
217			if item == "" {
218				continue
219			}
220			out = append(out, item)
221		}
222		if len(out) == 0 {
223			return nil
224		}
225		return out
226	}
