942	func decodeLegacyIntakePayload(payload string) (PreClaimIntakeResult, error) {
943		var out preClaimIntakePromptResult
944		if err := json.Unmarshal([]byte(payload), &out); err != nil {
945			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: decode result: %w", err)
946		}
947		switch strings.ToLower(strings.TrimSpace(out.Classification)) {
948		case "atomic", "ok", "ready", "actionable", "pass":
949			return PreClaimIntakeResult{Outcome: PreClaimIntakeActionableAtomic, Detail: strings.TrimSpace(out.Reasoning)}, nil
950		case "rewritten":
951			return PreClaimIntakeResult{
952				Outcome: PreClaimIntakeActionableButRewritten,
953				Detail:  strings.TrimSpace(out.Reasoning),
954				Rewrite: PreClaimIntakeRewrite{
955					Description:   strings.TrimSpace(out.Rewrite.Description),
956					Acceptance:    strings.TrimSpace(out.Rewrite.Acceptance),
957					ChangedFields: normalizePreClaimIntakeRewriteFields(out.Rewrite.ChangedFields),
958				},
959			}, nil
960		case "decomposable":
961			return PreClaimIntakeResult{Outcome: PreClaimIntakeTooLargeDecomposed, Detail: strings.TrimSpace(out.Reasoning)}, nil
962		case "ambiguous", "ambiguous_scope", "needs_human", "ambiguous_needs_human":
963			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: legacy classification %q removed by lifecycle migration; use outcome %q", out.Classification, PreClaimIntakeOperatorRequired)
964		case "":
965			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: missing classification")
966		default:
967			return PreClaimIntakeResult{}, fmt.Errorf(
968				"pre-claim intake: unknown classification %q: expected one of ready, needs_refine, needs_split, operator_required, system_unready",
969				out.Classification,
970			)
971		}
972	}
