// TestReadinessChecksSchema verifies that the readiness_checks JSON schema
// and the preClaimReadinessCheck decoder are aligned on the same contract.
// The schema is the single source of truth; drift between schema and decoder
// implementation is caught by this test.
func TestReadinessChecksSchema(t *testing.T) {
	schemaPath := filepath.Join("schema", "readiness-checks.schema.json")
	schemaBytes, err := ioutil.ReadFile(schemaPath)
	require.NoError(t, err, "failed to read schema file at %s", schemaPath)

	compiler := jsonschema.NewCompiler()
	schema, err := compiler.Compile(schemaBytes)
	require.NoError(t, err, "failed to compile schema")

	// Test cases represent the canonical verdict forms that the decoder accepts:
	// - JSON bool true  -> canonical "pass"
	// - JSON bool false -> canonical "fail"
	// - JSON string     -> lowercased, trimmed
	// - JSON null       -> empty string
	// - absent          -> empty string
	testCases := []struct {
		name       string
		payload    string
		shouldPass bool
	}{
		{
			name:       "verdict_bool_true",
			payload:    `[{"reason":"test","verdict":true,"evidence":"ok","checkable_before_attempt":true}]`,
			shouldPass: true,
		},
		{
			name:       "verdict_bool_false",
			payload:    `[{"reason":"test","verdict":false,"evidence":"ok","checkable_before_attempt":false}]`,
			shouldPass: true,
		},
		{
			name:       "verdict_string_pass",
			payload:    `[{"reason":"test","verdict":"pass","evidence":"ok"}]`,
			shouldPass: true,
		},
		{
			name:       "verdict_string_fail",
			payload:    `[{"reason":"test","verdict":"fail","evidence":"evidence of failure"}]`,
			shouldPass: true,
		},
		{
			name:       "verdict_string_ready",
			payload:    `[{"reason":"test","verdict":"ready","evidence":"ok"}]`,
			shouldPass: true,
		},
		{
			name:       "verdict_null",
			payload:    `[{"reason":"test","verdict":null,"evidence":"ok"}]`,
			shouldPass: true,
		},
		{
			name:       "verdict_absent",
			payload:    `[{"reason":"test","evidence":"ok"}]`,
			shouldPass: true,
		},
		{
			name:       "all_fields_present",
			payload:    `[{"reason":"missing_test","verdict":"fail","evidence":"no go test found","checkable_before_attempt":true}]`,
			shouldPass: true,
		},
		{
			name:       "minimal_fields",
			payload:    `[{}]`,
			shouldPass: true,
		},
		{
			name:       "empty_array",
			payload:    `[]`,
			shouldPass: true,
		},
		{
			name:       "multiple_checks",
			payload:    `[{"reason":"check1","verdict":"pass"},{"reason":"check2","verdict":"fail","evidence":"failed"}]`,
			shouldPass: true,
		},
		{
			name:       "extra_properties_invalid",
			payload:    `[{"reason":"test","verdict":"pass","extra_field":"should_fail"}]`,
			shouldPass: false,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			var data interface{}
			err := json.Unmarshal([]byte(tc.payload), &data)
			require.NoError(t, err, "failed to unmarshal test payload")

			validationErr := schema.Validate(data)
			if tc.shouldPass {
				require.NoError(t, validationErr, "schema validation should pass for %s", tc.name)
			} else {
				require.Error(t, validationErr, "schema validation should fail for %s", tc.name)
			}
		})
	}

	// Regression test: verify that the schema accepts the same forms that the
	// decoder accepts. This test checks the canonical coercion contract.
	t.Run("decoder_roundtrip", func(t *testing.T) {
		testPayloads := []struct {
			name          string
			payload       string
			expectedCheck preClaimReadinessCheck
		}{
			{
				name:    "bool_true_decodes_to_pass",
				payload: `[{"reason":"test","verdict":true}]`,
				expectedCheck: preClaimReadinessCheck{
					Reason:  "test",
					Verdict: "pass",
				},
			},
			{
				name:    "bool_false_decodes_to_fail",
				payload: `[{"reason":"test","verdict":false}]`,
				expectedCheck: preClaimReadinessCheck{
					Reason:  "test",
					Verdict: "fail",
				},
			},
			{
				name:    "string_verdict_passthrough",
				payload: `[{"reason":"test","verdict":"ready"}]`,
				expectedCheck: preClaimReadinessCheck{
					Reason:  "test",
					Verdict: "ready",
				},
			},
		}

		for _, tp := range testPayloads {
			t.Run(tp.name, func(t *testing.T) {
				// First, validate against schema
				var data interface{}
				err := json.Unmarshal([]byte(tp.payload), &data)
				require.NoError(t, err)
				err = schema.Validate(data)
				require.NoError(t, err, "payload should be valid against schema")

				// Then, verify decoder produces expected result
				var checks []preClaimReadinessCheck
				err = json.Unmarshal([]byte(tp.payload), &checks)
				require.NoError(t, err)
				require.Len(t, checks, 1)
				require.Equal(t, tp.expectedCheck.Reason, checks[0].Reason)
				require.Equal(t, tp.expectedCheck.Verdict, checks[0].Verdict)
			})
		}
	})
}
